const express = require('express');
const app = express();

// Middleware to parse JSON requests
app.use(express.json());

// Levels and rewards data
const levels = [
  { level: 1, scoreGoal: 50, timeGoal: 30 },
  // ... additional levels
];
const rewards = {
  scoreReward: 10,
  timeReward: 5,
};

// Complete level endpoint
app.post('/complete-level', (req, res) => {
  const { level, score, time } = req.body;

  // Validate level
  const levelData = levels.find(l => l.level === level);
  if (!levelData) {
    return res.status(400).json({ error: 'Invalid level' });
  }

  // Validate score and time
  if (score < levelData.scoreGoal || time > levelData.timeGoal) {
    return res.status(400).json({ error: 'Score or time not met' });
  }

  // Calculate rewards
  const scoreReward = rewards.scoreReward;
  const timeReward = rewards.timeReward;

  // Send rewards to client
  res.json({ scoreReward, timeReward });
});

// Claim rewards endpoint
app.post('/claim-rewards', (req, res) => {
  const { scoreReward, timeReward } = req.body;

  // Add rewards to user account
  // ... implement reward system here

  // Respond to client
  res.json({ message: 'Rewards claimed successfully' });
});

// Start server
app.listen(3000, () => {
  console.log('Server started on port 3000');
});